import streamlit as st
import pandas as pd
import plotly.express as px
import plotly.graph_objects as go

# ── Paleta oficial Dias+ ──────────────────────────────────────────────────────
TEAL_PRIMARY  = "#2DC5B4"
TEAL_DEEP     = "#0E7A8C"
TEAL_MEDIUM   = "#5BA8B8"
TEAL_DARK     = "#1A5A68"
DARK_BG       = "#0B3040"
DARK_MID      = "#0B2E3A"
SALMON        = "#C47A77"
NEUTRAL_700   = "#4A6670"
NEUTRAL_300   = "#D8E1E5"
WHITE         = "#FFFFFF"

COLOR_SCALE = [
    [0.00, DARK_BG],
    [0.25, TEAL_DARK],
    [0.60, TEAL_MEDIUM],
    [0.85, TEAL_PRIMARY],
    [1.00, WHITE],
]

LOGO_B64 = ""

# ── Config ────────────────────────────────────────────────────────────────────
st.set_page_config(
    page_title="Treinamentos | Dias+",
    page_icon="📚",
    layout="wide",
)

st.markdown(f"""
<style>
@import url('https://fonts.googleapis.com/css2?family=Barlow+Condensed:wght@300;400;600;700;800;900&display=swap');

html, body, [class*="css"] {{
    font-family: 'Barlow Condensed', sans-serif !important;
}}
.stApp {{
    background: linear-gradient(135deg, {DARK_MID} 0%, {TEAL_DARK} 100%);
    color: {WHITE};
}}
section[data-testid="stSidebar"] {{
    background: rgba(11, 46, 58, 0.95);
    border-right: 1px solid rgba(45, 197, 180, 0.25);
}}
section[data-testid="stSidebar"] * {{ color: {WHITE} !important; }}
[data-testid="metric-container"] {{
    background: rgba(255,255,255,0.07);
    backdrop-filter: blur(20px);
    -webkit-backdrop-filter: blur(20px);
    border: 1px solid rgba(45,197,180,0.30);
    border-radius: 16px;
    padding: 20px;
    box-shadow: 0 8px 32px rgba(0,0,0,0.25);
}}
[data-testid="metric-container"] label {{ color: {NEUTRAL_300} !important; font-size: 13px; letter-spacing: .06em; text-transform: uppercase; }}
[data-testid="metric-container"] [data-testid="stMetricValue"] {{ color: {WHITE} !important; font-weight: 800; font-size: 2rem; }}
h1,h2,h3,h4 {{ color: {WHITE}; font-weight: 800; text-transform: uppercase; letter-spacing: .04em; }}
.stTabs [data-baseweb="tab-list"] {{ background: rgba(255,255,255,0.05); border-radius: 12px; gap: 4px; }}
.stTabs [data-baseweb="tab"] {{ color: {NEUTRAL_300}; font-weight: 600; border-radius: 8px; }}
.stTabs [aria-selected="true"] {{ background: {TEAL_PRIMARY} !important; color: {DARK_BG} !important; }}
.stDataFrame {{ border-radius: 12px; overflow: hidden; }}
.stDownloadButton button {{
    background: {TEAL_PRIMARY}; color: {DARK_BG}; font-weight: 700;
    border-radius: 999px; border: none; padding: 8px 24px;
    text-transform: uppercase; letter-spacing: .06em;
}}
.stDownloadButton button:hover {{ background: {TEAL_MEDIUM}; }}
.stInfo {{ background: rgba(45,197,180,0.12); border-left: 4px solid {TEAL_PRIMARY}; border-radius: 8px; }}
.stAlert {{ border-radius: 12px; }}
</style>
""", unsafe_allow_html=True)

# ── Header com logo ───────────────────────────────────────────────────────────
st.markdown(f"""
<div style="background: linear-gradient(135deg, {DARK_MID} 0%, {TEAL_DARK} 100%);
            padding: 28px 36px; border-radius: 20px; margin-bottom: 28px;
            border: 1px solid rgba(45,197,180,0.25);
            box-shadow: 0 8px 32px rgba(0,0,0,0.35);
            display: flex; align-items: center; gap: 24px;">
    <img src="data:image/png;base64,{LOGO_B64}" style="height:56px; filter: drop-shadow(0 2px 8px rgba(0,0,0,.4));">
    <div>
        <div style="font-family:'Barlow Condensed',sans-serif; font-size:28px;
                    font-weight:900; color:{WHITE}; text-transform:uppercase; letter-spacing:.06em; line-height:1.1;">
            DASHBOARD DE TREINAMENTOS
        </div>
        <div style="font-family:'Barlow Condensed',sans-serif; font-size:14px;
                    color:{TEAL_PRIMARY}; letter-spacing:.1em; margin-top:4px;">
            GESTÃO DE PESSOAS · COBERTURA & ADERÊNCIA
        </div>
    </div>
</div>
""", unsafe_allow_html=True)


# ── Carregamento ──────────────────────────────────────────────────────────────
COLUNAS_PART  = ["nome", "filial", "treinamento", "data"]
COLUNAS_MOT   = ["nome", "filial"]

@st.cache_data(show_spinner="Processando planilha…")
def carregar_excel(arq):
    try:
        participantes = pd.read_excel(arq, sheet_name="participantes")
        motoristas    = pd.read_excel(arq, sheet_name="motoristas")
    except Exception as e:
        st.error(f"Erro ao ler o Excel: {e}")
        st.stop()

    participantes.columns = participantes.columns.str.lower().str.strip()
    motoristas.columns    = motoristas.columns.str.lower().str.strip()

    faltando_p = [c for c in COLUNAS_PART if c not in participantes.columns]
    faltando_m = [c for c in COLUNAS_MOT  if c not in motoristas.columns]
    if faltando_p or faltando_m:
        msgs = []
        if faltando_p:
            msgs.append(f"Aba 'participantes' sem colunas: {faltando_p}")
        if faltando_m:
            msgs.append(f"Aba 'motoristas' sem colunas: {faltando_m}")
        st.error("Planilha fora do padrão. " + " | ".join(msgs))
        st.stop()

    participantes["data"] = pd.to_datetime(participantes["data"], errors="coerce")
    return participantes, motoristas


# ── Sidebar ───────────────────────────────────────────────────────────────────
st.sidebar.markdown(f"""
<div style="font-family:'Barlow Condensed',sans-serif; font-size:22px;
            font-weight:800; color:{TEAL_PRIMARY}; text-transform:uppercase;
            letter-spacing:.06em; margin-bottom:8px;">
    ⚙ Configurações
</div>
""", unsafe_allow_html=True)

arquivo = st.sidebar.file_uploader("Enviar Excel", type=["xlsx"],
    help="Arquivo com abas 'participantes' e 'motoristas'")

if arquivo is None:
    st.info("Faça upload do arquivo Excel para iniciar.")
    st.stop()

df, base = carregar_excel(arquivo)

st.sidebar.markdown(f"<div style='color:{TEAL_PRIMARY};font-weight:700;font-size:16px;margin-top:16px;'>FILTROS</div>", unsafe_allow_html=True)

filial = st.sidebar.selectbox(
    "Filial",
    ["Todas"] + sorted(df["filial"].dropna().unique()),
    help="Filtra todas as métricas pela filial selecionada",
)

if filial != "Todas":
    df   = df[df["filial"] == filial]
    base = base[base["filial"] == filial]

treinamentos = st.sidebar.multiselect(
    "Treinamentos",
    sorted(df["treinamento"].dropna().unique()),
    help="Deixe em branco para exibir todos",
)
if treinamentos:
    df = df[df["treinamento"].isin(treinamentos)]

data_min = df["data"].min()
data_max = df["data"].max()

periodo = st.sidebar.date_input(
    "Período",
    [data_min, data_max],
    help="Filtro por data de realização do treinamento",
)

if len(periodo) == 2:
    inicio, fim = periodo
    df = df[(df["data"] >= pd.Timestamp(inicio)) & (df["data"] <= pd.Timestamp(fim))]
elif len(periodo) == 1:
    st.sidebar.warning("Selecione a data de início e fim.")

if df.empty:
    st.warning("Nenhum dado encontrado com os filtros aplicados. Ajuste os filtros no menu lateral.")
    st.stop()


# ── KPIs ──────────────────────────────────────────────────────────────────────
base_total   = base["nome"].nunique()
treinados    = df["nome"].nunique()
nao_trein    = max(base_total - treinados, 0)
cobertura    = round((treinados / base_total) * 100, 1) if base_total else 0

cor_cobertura = TEAL_PRIMARY if cobertura >= 70 else (SALMON if cobertura < 50 else "#D4B44A")

c1, c2, c3, c4 = st.columns(4)
c1.metric("Treinados",     treinados,  help="Pessoas únicas que participaram de ao menos 1 treinamento")
c2.metric("Não treinados", nao_trein,  help="Base − treinados no período/filtros selecionados",
          delta=f"-{nao_trein}" if nao_trein > 0 else None,
          delta_color="inverse")
c3.metric("Cobertura",     f"{cobertura}%", help="Treinados / Base total × 100")
c4.metric("Base total",    base_total, help="Total de motoristas na base para a filial selecionada")


# ── Layout padrão dos gráficos ────────────────────────────────────────────────
CHART_BG = dict(
    paper_bgcolor="rgba(11,46,58,0.6)",
    plot_bgcolor ="rgba(11,46,58,0.0)",
    font=dict(color=WHITE, family="Barlow Condensed"),
    margin=dict(t=48, b=32, l=16, r=16),
)

def aplicar_tema(fig):
    fig.update_layout(**CHART_BG)
    fig.update_xaxes(gridcolor="rgba(255,255,255,0.08)", linecolor="rgba(255,255,255,0.15)")
    fig.update_yaxes(gridcolor="rgba(255,255,255,0.08)", linecolor="rgba(255,255,255,0.15)")
    return fig


# ── Tabs ──────────────────────────────────────────────────────────────────────
tab1, tab2, tab3, tab4, tab5 = st.tabs([
    "📊 Visão Geral", "🏢 Filiais", "📚 Treinamentos",
    "👤 Participantes", "📈 Evolução",
])

# ── Tab 1 — Visão Geral ───────────────────────────────────────────────────────
with tab1:
    col1, col2 = st.columns([2, 1])

    with col1:
        cont = df["treinamento"].value_counts().reset_index()
        cont.columns = ["Treinamento", "Participações"]

        fig = px.bar(
            cont, x="Treinamento", y="Participações",
            color="Participações", color_continuous_scale=COLOR_SCALE,
            title="Participações por Treinamento",
        )
        fig.update_traces(marker_line_width=0, marker_cornerradius=6)
        aplicar_tema(fig)
        st.plotly_chart(fig, use_container_width=True)

    with col2:
        gauge = go.Figure(go.Indicator(
            mode="gauge+number",
            value=cobertura,
            number={"suffix": "%", "font": {"size": 52, "color": WHITE}},
            title={"text": "COBERTURA", "font": {"size": 16, "color": NEUTRAL_300}},
            gauge={
                "axis": {"range": [0, 100], "tickcolor": NEUTRAL_300},
                "bar":  {"color": cor_cobertura},
                "steps": [
                    {"range": [0,  50], "color": "rgba(196,122,119,0.18)"},
                    {"range": [50, 70], "color": "rgba(212,180,74,0.15)"},
                    {"range": [70,100], "color": "rgba(45,197,180,0.15)"},
                ],
                "threshold": {"line": {"color": WHITE, "width": 2}, "value": 70},
            },
        ))
        gauge.update_layout(**CHART_BG)
        st.plotly_chart(gauge, use_container_width=True)

# ── Tab 2 — Filiais ───────────────────────────────────────────────────────────
with tab2:
    cobertura_filial = df.groupby("filial")["nome"].nunique().reset_index()
    cobertura_filial.columns = ["Filial", "Participantes"]

    fig = px.bar(
        cobertura_filial, x="Filial", y="Participantes",
        color="Participantes", color_continuous_scale=COLOR_SCALE,
        title="Participantes únicos por Filial",
    )
    fig.update_traces(marker_line_width=0, marker_cornerradius=6)
    aplicar_tema(fig)
    st.plotly_chart(fig, use_container_width=True)

# ── Tab 3 — Treinamentos (heatmap) ───────────────────────────────────────────
with tab3:
    heat = pd.pivot_table(
        df, index="filial", columns="treinamento",
        values="nome", aggfunc="count", fill_value=0,
    )

    fig = px.imshow(
        heat, text_auto=True,
        color_continuous_scale=COLOR_SCALE,
        title="Participações: Filial × Treinamento",
        aspect="auto",
    )
    fig.update_layout(**CHART_BG)
    st.plotly_chart(fig, use_container_width=True)

# ── Tab 4 — Participantes ─────────────────────────────────────────────────────
with tab4:
    filiais_disp = sorted(df["filial"].dropna().unique())
    if not filiais_disp:
        st.info("Nenhuma filial disponível com os filtros atuais.")
    else:
        filial_drill = st.selectbox("Filial", filiais_disp, key="drill_filial")
        d1 = df[df["filial"] == filial_drill]

        trein_disp = sorted(d1["treinamento"].dropna().unique())
        if not trein_disp:
            st.info("Nenhum treinamento disponível para esta filial.")
        else:
            treinamento_drill = st.selectbox("Treinamento", trein_disp, key="drill_trein")
            d2 = d1[d1["treinamento"] == treinamento_drill]

            if d2.empty:
                st.info("Nenhum participante encontrado para a seleção.")
            else:
                st.dataframe(d2.reset_index(drop=True), use_container_width=True)

# ── Tab 5 — Evolução acumulada ─────────────────────────────────────────────────
with tab5:
    evo = (
        df.groupby(df["data"].dt.date)
        .size()
        .cumsum()
        .reset_index(name="Acumulado")
    )
    evo.columns = ["Data", "Acumulado"]

    fig = px.line(
        evo, x="Data", y="Acumulado",
        markers=True,
        title="Participações acumuladas ao longo do tempo",
        color_discrete_sequence=[TEAL_PRIMARY],
    )
    fig.update_traces(line_width=2.5, marker_size=6)
    aplicar_tema(fig)
    st.plotly_chart(fig, use_container_width=True)


# ── Exportar ──────────────────────────────────────────────────────────────────
filtros_ativos = []
if filial != "Todas":
    filtros_ativos.append(f"filial={filial}")
if treinamentos:
    filtros_ativos.append(f"{len(treinamentos)} treinamento(s)")
if len(periodo) == 2:
    filtros_ativos.append(f"{periodo[0]} a {periodo[1]}")

aviso = f" ({', '.join(filtros_ativos)})" if filtros_ativos else " (todos os registros)"

csv = df.to_csv(index=False, sep=";").encode("utf-8-sig")
st.download_button(
    f"⬇ Exportar CSV{aviso}",
    csv,
    "treinamentos_dias.csv",
    "text/csv",
)

